import React, { useState } from 'react';
import Barcode from 'react-barcode';
import { BiPrinter } from 'react-icons/bi';
import { useParams } from 'react-router-dom';
import s from './code-print.module.scss';

const CodePrint = () => {
  const { code, name, price } = useParams();
  const [qty, setQty] = useState(1);

  // создаём массив нужной длины для повторения ярлыков
  const labels = Array.from({ length: qty });

  return (
    <div className={s.wrapper}>
      {labels.map((_, i) => (
        <div key={i} className={s.label}>
          <h3 className={s.title}>{name}</h3>
          <p className={s.price}>Стоимость: {price}&nbsp;сом</p>

          {/* Штрих-код как <canvas /> — XPrinter печатает без искажений */}
          <Barcode
            value={code}
            renderer="canvas"
            width={1.4}     /* ширина полосы */
            height={45}     /* высота штрих-кода */
            fontSize={14}
            margin={0}
            className={s.barcode}
          />
        </div>
      ))}

      {/* UI-контролы (скрываются при печати) */}
      <div className={s.controls}>
        <input
          type="number"
          min="1"
          value={qty}
          onChange={e => setQty(Math.max(+e.target.value, 1))}
        />
        <button onClick={() => window.print()}>
          Распечатать&nbsp;<BiPrinter size={18} />
        </button>
      </div>
    </div>
  );
};

export default CodePrint;
